STRINGS.UI =
{
	BULLET_POINT = "<p img='images/ui_ftf/point.tex' color=0 scale=0.3>",
	BULLET_DASH = "<p img='images/ui_ftf/dash.tex' color=0 scale=0.4>",
	QUANTITY = "{name} (x{count})",        -- How we display named quantities.
